const body = $input.item.json.body;
const question = (body.question || '').trim();
const studentName = (body.studentName || 'Anonymous').trim();
const history = Array.isArray(body.history) ? body.history : [];

if (!question) throw new Error('Missing required field: question');

const stopWords = new Set([
  'what','is','are','the','a','an','of','in','to','and','or',
  'how','does','do','can','why','when','where','which','who',
  'me','my','explain','describe','tell','about','difference',
  'between','give','example','examples','please','define'
]);

const queryKeywords = question
  .toLowerCase()
  .replace(/[^a-z0-9\s]/g, '')
  .split(/\s+/)
  .filter(w => w.length > 2 && !stopWords.has(w));

// Extract keywords from last history question too
const historyKeywords = history.length > 0
  ? (history[history.length-1].question || '')
      .toLowerCase().replace(/[^a-z0-9\s]/g,'').split(/\s+/)
      .filter(w => w.length > 2 && !stopWords.has(w))
  : [];

// Merge both for broader retrieval
const allKeywords = [...new Set([...queryKeywords, ...historyKeywords])];

return {
  json: {
    question,
    studentName,
    history,
    queryKeywords: allKeywords,
    queryKeywordsStr: allKeywords.join(', '),
  }
};

const queryKeywords = $('Code in JavaScript').item.json.queryKeywords;
const question = $('Code in JavaScript').item.json.question;
const studentName = $('Code in JavaScript').item.json.studentName;

const allEntries = $input.all();

const scored = allEntries.map(item => {
  const entry = item.json;
  const kbText = `${entry.Keywords} ${entry.Content} ${entry.Topic}`.toLowerCase();
  const matchCount = queryKeywords.filter(kw => kbText.includes(kw)).length;
  const topicBonus = queryKeywords.some(kw =>
    (entry.Topic || '').toLowerCase().includes(kw)) ? 1 : 0;
  return {
    ...entry,
    _score: matchCount + topicBonus,
  };
}).filter(e => e._score > 0)
  .sort((a, b) => b._score - a._score)
  .slice(0, 3);

// Get top score
const topScore = scored.length > 0 ? scored[0]._score : 0;

// Only include entries with score >= 2
const highConfidence = scored.filter(e => e._score >= 2);

let contextBlock = '';
let sources = [];

if (highConfidence.length > 0) {
  highConfidence.forEach((e, idx) => {
    contextBlock += `[${idx+1}] ${e.Content} (Source: ${e.Source})\n\n`;
    sources.push(`${e.EntryID} — ${e.Topic} (${e.Source})`);
  });
}

return {
  json: {
    question,
    studentName,
    contextFound: highConfidence.length > 0,      // true only if score >= 2
    lowConfidence: scored.length > 0 && highConfidence.length === 0, // matches exist but all < 2
    contextBlock,
    sources,
    retrievedCount: highConfidence.length,
    topScore,
  }
};

const retrieval = $('Retrieval Code').item.json;
const history = $('Code in JavaScript').item.json.history;

// Build alternating user/assistant history pairs
const historyMessages = [];
history.forEach(turn => {
  if (turn.question) historyMessages.push({ role: 'user', content: turn.question });
  if (turn.answer) historyMessages.push({ role: 'assistant', content: turn.answer });
});

// Current question with injected context
const currentMessage = {
  role: 'user',
  content: `CONTEXT:\n${retrieval.contextBlock}\nQUESTION: ${retrieval.question}\nAnswer based strictly on the context above.`
};

return {
  json: {
    ...retrieval,
    messages: [...historyMessages, currentMessage],
    fullPrompt: [...historyMessages, currentMessage]
      .map(m => `${m.role.toUpperCase()}: ${m.content}`)
      .join('\n\n')
  }
};
